;EACA;;AAEA;EACI;EACA;EACA;EACA;;AAEJ;EAEI;EACA;;AACA;EACI;EACA;EACA;EACA;EACA;;AAIZ;EACI;EACA;EACA;;AACA;EACI;;AAEJ;EACI;EACA;;AAEJ;EACI;EACA;;AAEJ;EACI;EACA;;AAMR;EACI;;AAGA;EACI;;AAEJ;EACI,aJ/FC;EIgGD,OJnIJ;;;AIyIZ;EACI;IACI;;EAGJ;IACI;IACA;IACA;;EAEA;IACI;;EAIR;IACI;IACA;IACA;IACA;;EAEA;IACI;IACA;IACA;IACA;IACA,kBJ/JJ;IIgKI;;EAEA;IACI;IACA;IACA;IAEA,WJ7JR;;EIgKI;IACI,aJ3IA;II4IA;;EAEA;IACI;IACA;IACA;IACA;;EAKZ;IACI;IACA;IACA;IACA;IACA;IACA;;EAEA;IAII;IACA","sourcesContent":["*, *:before, *:after{\r\n    box-sizing: border-box;\r\n    cursor: none !important;\r\n  }\r\n  \r\n  html, body, div, span, object, iframe, figure, h1, h2, h3, h4, h5, h6, p, blockquote, pre, a, code, em, img, small, strike, strong, sub, sup, tt, b, u, i, ol, ul, li, fieldset, form, label, table, caption, tbody, tfoot, thead, tr, th, td, main, canvas, embed, footer, header, nav, section, video{\r\n    margin: 0;\r\n    padding: 0;\r\n    border: 0;\r\n    font: inherit;\r\n    font-size:62.5%;\r\n    vertical-align: baseline;\r\n    text-rendering: optimizeLegibility;\r\n    -webkit-font-smoothing: antialiased;\r\n    text-size-adjust: none;\r\n    color:#1e2736;\r\n  }\r\n\r\n  address{\r\n    font-style: normal;\r\n  }\r\n\r\n  html{\r\n    scroll-behavior: smooth;\r\n  }\r\n  \r\n  footer, header, nav, section, main{\r\n    display: block;\r\n  }\r\n  \r\n  body{\r\n    line-height: 1;\r\n\r\n    &::selection {           \r\n      background: #1e2736;\r\n      color: #fff;\r\n    }\r\n    &::-moz-selection {           \r\n      background: #1e2736;\r\n      color: #fff;\r\n    }\r\n    &::-ms-selection {           \r\n      background: #1e2736;\r\n      color: #fff;\r\n    }\r\n  }\r\n  \r\n  ul{\r\n    list-style: none;\r\n  }\r\n  \r\n  blockquote, q{\r\n    quotes: none;\r\n  }\r\n  \r\n  blockquote:before, blockquote:after, q:before, q:after{\r\n    content: '';\r\n    content: none;\r\n  }\r\n  \r\n  table{\r\n    border-collapse: collapse;\r\n    border-spacing: 0;\r\n  }\r\n  \r\n  input{\r\n    // -webkit-appearance: none;\r\n    border-radius: 0;\r\n  }\r\n\r\n  a {\r\n    text-decoration: none;\r\n  }\r\n  ","@keyframes float1 {\r\n    0% { transform: translate(0, 0) rotate(0deg); }\r\n    20% { transform: translate(100px, -80px) rotate(36deg); }\r\n    40% { transform: translate(-60px, 100px) rotate(72deg); }\r\n    60% { transform: translate(120px, 60px) rotate(108deg); }\r\n    80% { transform: translate(-40px, -100px) rotate(144deg); }\r\n    100% { transform: translate(0, 0) rotate(180deg); }\r\n}\r\n@keyframes float2 {\r\n    0% { transform: translate(0, 0) scale(1); }\r\n    16% { transform: translate(-80px, -60px) scale(1.1); }\r\n    32% { transform: translate(60px, -100px) scale(0.9); }\r\n    48% { transform: translate(-120px, 80px) scale(1.05); }\r\n    64% { transform: translate(100px, 90px) scale(0.95); }\r\n    80% { transform: translate(0, -60px) scale(1); }\r\n    100% { transform: translate(0, 0) scale(1); }\r\n}\r\n@keyframes float3 {\r\n    0% { transform: translate(0, 0) rotate(0deg) scale(1); }\r\n    25% { transform: translate(80px, -120px) rotate(45deg) scale(1.1); }\r\n    50% { transform: translate(-100px, -80px) rotate(90deg) scale(0.9); }\r\n    75% { transform: translate(40px, 60px) rotate(135deg) scale(1); }\r\n    100% { transform: translate(0, 0) rotate(180deg) scale(1); }\r\n}\r\n@keyframes float4 {\r\n    0% { transform: translate(0, 0); }\r\n    25% { transform: translate(-120px, 100px); }\r\n    50% { transform: translate(80px, -80px); }\r\n    75% { transform: translate(-40px, 120px); }\r\n    100% { transform: translate(0, 0); }\r\n}\r\n@keyframes float5 {\r\n    0% { transform: translate(0, 0) rotate(0deg); }\r\n    20% { transform: translate(-80px, 120px) rotate(36deg); }\r\n    40% { transform: translate(100px, 40px) rotate(72deg); }\r\n    60% { transform: translate(-120px, -80px) rotate(108deg); }\r\n    80% { transform: translate(60px, -60px) rotate(144deg); }\r\n    100% { transform: translate(0, 0) rotate(180deg); }\r\n}\r\n@keyframes float6 {\r\n    0% { transform: translate(0, 0) scale(1); }\r\n    30% { transform: translate(160px, -100px) scale(1.15); }\r\n    60% { transform: translate(-80px, 120px) scale(0.85); }\r\n    80% { transform: translate(80px, -40px) scale(1); }\r\n    100% { transform: translate(0, 0) scale(1); }\r\n}\r\n@keyframes float7 {\r\n    0% { transform: translate(0, 0); }\r\n    28% { transform: translate(-100px, -120px); }\r\n    56% { transform: translate(60px, 80px); }\r\n    80% { transform: translate(-120px, 40px); }\r\n    100% { transform: translate(0, 0); }\r\n}\r\n@keyframes float8 {\r\n    0% { transform: translate(0, 0) rotate(0deg) scale(1); }\r\n    16% { transform: translate(80px, 100px) rotate(30deg) scale(1.08); }\r\n    32% { transform: translate(-120px, 60px) rotate(60deg) scale(0.92); }\r\n    48% { transform: translate(140px, -80px) rotate(90deg) scale(1.05); }\r\n    64% { transform: translate(-60px, -120px) rotate(120deg) scale(0.95); }\r\n    80% { transform: translate(0, 80px) rotate(150deg) scale(1); }\r\n    100% { transform: translate(0, 0) rotate(180deg) scale(1); }\r\n}\r\n\r\n.bg-animation-contactPress{\r\n    position:absolute;\r\n    left:0\r\n}\r\n\r\n// .residence-permit__illustration-part{\r\n//     &-1{\r\n//         outline: 1px dashed pink;\r\n//     };\r\n//     &-2{\r\n//         outline: 1px dashed peachpuff;\r\n//     };\r\n//     &-3{\r\n//         outline:1px dashed darkseagreen;\r\n//     };\r\n//     &-4{\r\n//         outline:1px dashed salmon;\r\n//     };  \r\n// }","@use \"./vars\";\r\n@use \"./mixins\" as m;\r\n\r\n// @font-face {\r\n//     font-family: \"Raleway-Regular\";\r\n//     font-weight: 400;\r\n//     src: \r\n//     // url(\"/src/fonts/FONT_NAME.woff2\") format(woff2),\r\n//     // url(\"/src/fonts/FONT_NAME.woff\") format(woff),\r\n//     url(\"/src/fonts/Raleway-Regular.ttf\")\r\n// }\r\n\r\n@font-face {\r\nfont-family: \"Raleway-Regular\";\r\nsrc: url(/src/fonts/Raleway-Regular.ttf);\r\n}\r\n@font-face {\r\n    font-family: \"Raleway-Medium\";\r\n    src: url(/src/fonts/Raleway-Medium.ttf);\r\n}\r\n@font-face {\r\n    font-family: \"Raleway-Semibold\";\r\n    src: url(/src/fonts/Raleway-SemiBold.ttf);\r\n}\r\n@font-face {\r\n    font-family: \"Raleway-Bold\";\r\n    src: url(/src/fonts/Raleway-Bold.ttf);\r\n}\r\n@font-face {\r\n    font-family: \"Raleway-Regular-Italic\";\r\n    src: url(/src/fonts/Raleway-Italic.ttf);\r\n}\r\n@font-face {\r\n    font-family: \"Raleway-Light\";\r\n    src: url(/src/fonts/Raleway-Light.ttf);\r\n}\r\n\r\nh1, h2, h3, h4, h5, p, a, button, ul, ol {\r\nfont-family: vars.$mainFontRegular;\r\n}\r\n\r\nh1 {\r\n    font-size: vars.$h1Size;\r\n}\r\nh2 {\r\n    font-size: vars.$h2Size;\r\n}\r\nh3 {\r\n    font-size: vars.$h3Size;\r\n}\r\nh4 {\r\n    font-size: vars.$h4Size;\r\n}\r\nh5 {\r\n    font-size: vars.$h5Size;\r\n}\r\np, a, button, ol, ul {\r\n    font-size: vars.$pSize;\r\n}\r\n\r\n@include m.mobile{\r\n    p,a,button,ol,ul{\r\n        font-size: vars.$pSize * 0.9;\r\n    }\r\n    h3{\r\n        font-size: vars.$h3Size * 0.75;\r\n    }\r\n    h2{\r\n        font-size: vars.$h2Size * 0.50;\r\n    }\r\n    h5{\r\n        font-size: vars.$h5Size * 0.8;\r\n    }\r\n\r\n}\r\n\r\nstrong, .special-text, .bold-text {\r\n    font-family: vars.$mainFontBold;\r\n    font-size: 1em;\r\n}\r\n\r\n.medium-text {\r\n    font-family: vars.$mainFontMedium;\r\n    font-size: 1em;\r\n}\r\n.semibold-text {\r\n    font-family: vars.$mainFontSemibold;\r\n    font-size: 1em;\r\n}\r\n\r\n.special-text {\r\n    color: vars.$primaryColor;\r\n}\r\n.special-text_inverted {\r\n    color: vars.$primaryInvertedColor;\r\n}\r\n\r\n.underlined-text {\r\n    text-decoration: underline;\r\n    font-size: 1em;\r\n}\r\n.uppercased-text {\r\n    text-transform: uppercase;\r\n    font-size: 1em;\r\n}\r\n\r\n.italic-text{\r\n    font-family: vars.$mainFontItalic;\r\n    font-size: 1em;\r\n}\r\n\r\n.bold-text{\r\n    font-family: vars.$mainFontBold;\r\n    font-size: 1em;\r\n}","// Colors\r\n$primaryColor: #1a6eff;\r\n$primaryTransparentColor: #5292ff5b;\r\n$primaryInvertedColor: #ef9e00;\r\n\r\n$secondaryColor: #60a2ff;\r\n$lightColor: #e7effe;\r\n$borderColor: #d7deef;\r\n$darkColor: #1e2736;\r\n$greyColor: #434c5b;\r\n$lightGreyColor: #646d83;\r\n\r\n$black: #000;\r\n$white: #fff;\r\n\r\n$primaryBtnHover: #0050d9;\r\n$blueShadowColor: #d0dfff;\r\n\r\n// Sizes\r\n$h1Size:8.1rem;\r\n$h2Size:5.4rem;\r\n$h3Size:3.6rem;\r\n$h4Size:2.4rem;\r\n$h5Size:2rem;\r\n$h6Size:1.8rem;\r\n$pSize:1.6rem;\r\n\r\n$smallFontSize:1.4rem;\r\n$featureMarkSize:2.8rem;\r\n$badgeFontSize:1.3rem;\r\n\r\n// Screens\r\n$mobile: 767px; \r\n$tablet: 1023px;\r\n$desktop: 1990px;\r\n\r\n// Animation speed\r\n$fastestAnimation: 0.012s;\r\n$fastAnimation: 0.13s;\r\n$normalAnimation: 0.24s;\r\n$slowAnimation: 0.33s;\r\n\r\n// Font\r\n\r\n$mainFontRegular:\"Raleway-Regular\";\r\n$mainFontMedium:\"Raleway-Medium\";\r\n$mainFontSemibold:\"Raleway-Semibold\";\r\n$mainFontBold:\"Raleway-Bold\";\r\n$mainFontItalic:\"Raleway-Regular-Italic\";\r\n$mainFontLight:\"Raleway-Light\";\r\n\r\n// Bubbles\r\n$bubbleOneColor: #60a2ff;\r\n$bubbleTwoColor: #5292ff5b;\r\n","@use \"./vars\";\r\n\r\n// Adaptive base\r\n\r\n@mixin mobile{\r\n    @media (max-width: vars.$mobile) {\r\n        @content;\r\n    }\r\n}\r\n\r\n@mixin tablet{\r\n    @media (max-width: vars.$tablet) {\r\n        @content;\r\n    }\r\n}\r\n\r\n@mixin desktop{\r\n    @media (min-width: vars.$tablet) {\r\n        @content;\r\n    }\r\n}","@use \"../base/vars\";\r\n@use \"./mixins\" as m;\r\n\r\n#cursor, #aura {\r\n    position: fixed;\r\n    border-radius: 100%;    \r\n    user-select: none;\r\n    pointer-events: none;\r\n    \r\n    z-index:9999;\r\n    translate: -50% -50%;\r\n    \r\n    @include m.mobile{\r\n        display: none;\r\n    }\r\n}\r\n\r\n#aura {\r\n    width: 32px;\r\n    height: 32px;\r\n    border: 1px solid #1a6eff48;\r\n    background-color: #1a6eff18;\r\n    transition: .22s cubic-bezier(.73,-1.07,.15,1.88) transform, .2s cubic-bezier(.73,-1.07,.15,1.88) opacity;\r\n}\r\n#aura.hovered {\r\n    transform: scale(1.5);\r\n    border: 1px solid #1A6EFF96;\r\n    \r\n    // Пара идей для наведения\r\n\r\n    // backdrop-filter: invert(1);\r\n\r\n    // backdrop-filter: blur(1px);\r\n\r\n    // background: conic-gradient(\r\n    //     from 0deg, \r\n    //     rgba(255,0,150,0.1), \r\n    //     rgba(0,255,255,0.1), \r\n    //     rgba(255,255,0,0.1), \r\n    //     rgba(255,0,150,0.1)\r\n    // );\r\n    // backdrop-filter: hue-rotate(45deg) saturate(1.3);\r\n\r\n    background: \r\n        radial-gradient(circle at 30% 30%, rgba(255, 51, 0, 0.1) 0%, transparent 50%),\r\n        radial-gradient(circle at 70% 70%, rgba(4, 0, 255, 0.1) 0%, transparent 50%);\r\n    backdrop-filter: contrast(1.2) brightness(1.1);\r\n\r\n    border: 1px solid rgba(255,255,255,0.3);\r\n    box-shadow: \r\n        0 0 20px rgba(26,110,255,0.3),\r\n        inset 0 0 20px rgba(255,255,255,0.1);\r\n}\r\n\r\n#cursor {\r\n    width: 7px;\r\n    height: 7px;\r\n    background-color: #1a6eff7e;\r\n    transition: .5s cubic-bezier(.73,-1.07,.15,1.88) transform, .2s cubic-bezier(.73,-1.07,.15,1.88) opacity;\r\n    box-shadow: \r\n        0 0 10px vars.$secondaryColor,\r\n        0 0 20px vars.$secondaryColor,\r\n        0 0 30px vars.$secondaryColor,\r\n        0 0 40px vars.$secondaryColor;\r\n    background-color: #1a6eff;\r\n}\r\n#cursor.hidden {\r\n    opacity: 0;\r\n}\r\n\r\n#aura.clicked {\r\n    transition: 0.1s;\r\n    transform: scale(1.3);\r\n    opacity: 0.7;\r\n}","@use \"./vars\";\r\n@use \"./mixins\" as m;\r\n\r\n.service-card {\r\n    // max-width: 1000px;\r\n    display: flex;\r\n    flex-direction: column;\r\n    padding: 3rem; \r\n    gap: 2rem;\r\n    height: 100%;\r\n    &__numlist{\r\n        & > li{\r\n            color:vars.$greyColor;\r\n            font-family: vars.$mainFontMedium;\r\n            margin-top: 0;\r\n            font-size: 1.6rem;\r\n            margin-left: 2rem;\r\n        }\r\n    }\r\n\r\n    &--classic {\r\n        background-color: vars.$white;\r\n        border: 1px solid vars.$borderColor;\r\n        border-radius: 2rem;\r\n        box-shadow: 0 0 30px vars.$blueShadowColor;\r\n    }\r\n    &--alternative{\r\n        background: linear-gradient(\r\n            180deg, vars.$primaryColor, #104299);\r\n        color: #fff;\r\n        border-radius: 1.5rem;\r\n        & > header{\r\n            & > span, & > h3{\r\n                color: #fff;\r\n            }\r\n            & > .service-card__title{\r\n                text-decoration: underline;\r\n            }\r\n            & > .service-card__icon{\r\n                background-color: vars.$secondaryColor;\r\n            }\r\n        }\r\n        & > p {\r\n            font-family: vars.$mainFontLight;\r\n            color: #fff;\r\n        }\r\n    }\r\n    &--mini {\r\n        display: block;\r\n        @extend .service-card--classic;\r\n        color: #000;\r\n        padding: 2rem;\r\n\r\n        & > .service-card__title{\r\n            margin-top: 2rem;\r\n            font-family: vars.$mainFontBold;\r\n        }\r\n        & > .service-card__subtitle{\r\n            font-family: vars.$mainFontMedium;\r\n            font-size: 1.4rem;\r\n            color: vars.$greyColor;\r\n        }\r\n\r\n    }\r\n    &--exclusive {\r\n        border: 1px solid vars.$borderColor;\r\n        border-radius: 2rem;\r\n        & > header {\r\n            display: grid;\r\n            grid-template-columns: 72px 1fr;\r\n            grid-template-rows: 1fr 0.4fr;\r\n            gap: 0;\r\n            column-gap: 1.6rem;\r\n\r\n            & > .service-card__title, & > .service-card__subtitle{\r\n                align-self: end;\r\n            }\r\n\r\n            & > .service-card__icon {\r\n                grid-row: 1 / span 2;\r\n            }\r\n        }\r\n    }\r\n    &--dark {\r\n        background-color: vars.$darkColor;\r\n        border: 1px solid vars.$darkColor;\r\n        border-radius: 1rem;\r\n        color: vars.$white;\r\n\r\n        & > p, h4, h3, h2, h1, a {\r\n            color: #fff;\r\n        }\r\n\r\n        & > .card__benefit {\r\n            &::before {\r\n                content: url(/src/graphics/png/benefit-icon_dark.png);\r\n            }\r\n        }\r\n        & > .card__feature {\r\n            &::before {\r\n                color: vars.$primaryInvertedColor;\r\n            }\r\n        }\r\n    }\r\n    &--dark-exclusive {\r\n        @extend .service-card--dark;\r\n        justify-content: space-between;\r\n        border-radius: 2rem;\r\n        & > header {\r\n            display: grid;\r\n            grid-template-columns: auto 1fr;\r\n            gap: 0;\r\n            column-gap: 1.6rem;\r\n            & > .service-card__title{\r\n                align-self: center;\r\n            }\r\n            & > img{\r\n                background-color: #104299;\r\n            }\r\n        }\r\n        & > .service-card__text{\r\n            font-family: vars.$mainFontRegular;\r\n            min-height: 1lh\r\n        }\r\n    }\r\n    &--logistics {\r\n        border: 1px solid vars.$borderColor;\r\n        height: auto;\r\n        border-radius: 2rem;\r\n        margin: 2rem;\r\n    }\r\n    &--unique{\r\n        padding: 2rem;\r\n    }\r\n    &--glow{\r\n        position: relative;\r\n        z-index:50;\r\n        @extend .service-card--logistics;\r\n        box-shadow: 0 0 20px vars.$primaryTransparentColor;\r\n        border: none;\r\n        margin-left: 0;\r\n        margin-right: 4rem;\r\n        & > h4{\r\n            font-size: 18px;\r\n            font-family: vars.$mainFontMedium;\r\n        }\r\n    }\r\n    &--autoheight{\r\n        height: auto;\r\n    }\r\n    &--base{\r\n        display: flex;\r\n        gap: 2rem;\r\n        flex-direction: column;\r\n        padding: 2rem;\r\n        background-color: #ffffffbd;\r\n        border-radius: 2rem;\r\n        backdrop-filter: blur(12px);\r\n        border: 1px solid #ffffff;\r\n    }\r\n\r\n\r\n    &__icon{\r\n        width: 80px;\r\n        padding: 1.8rem;\r\n        background-color: vars.$lightColor;\r\n        border-radius: 1.5rem;\r\n    }\r\n\r\n    &__header{\n        display: grid;\n        position: relative;\n        gap: 1.2rem;\n        &--mini{\n            display: grid;\n            grid-template-columns: 80px minmax(0, 1fr);\n            grid-template-areas:\n                \"price price\"\n                \"timeline timeline\"\n                \"icon title\";\n            column-gap: 1.2rem;\n            row-gap: 0.6rem;\n            align-items: start;\n\n            & > .service-card__price-tag,\n            & > .service-card__timeline-tag{\n                position: static;\n                right: auto;\n                text-shadow: none;\n                line-height: 1.25;\n            }\n\n            & > .service-card__price-tag{\n                grid-area: price;\n                justify-self: start;\n            }\n\n            & > .service-card__timeline-tag{\n                grid-area: timeline;\n                justify-self: start;\n                translate: none;\n            }\n\n            & > .service-card__icon{\n                grid-area: icon;\n            }\n\n            & > .service-card__title{\n                grid-area: title;\n                align-self: center;\n                margin: 0;\n            }\n        }\n    }\n    &__title{\r\n        font-family: vars.$mainFontMedium;\r\n    }\r\n    &__description{\r\n        @include m.desktop{\r\n            font-size: vars.$h6Size;\r\n        }\r\n    } \r\n    &__subtitle {\r\n        font-family: vars.$mainFontMedium;\r\n        &--grey {\r\n            min-height: 2lh;\r\n            font-family: vars.$mainFontMedium;\r\n            color: vars.$greyColor;\r\n        }\r\n    }\r\n    &__text{\r\n        font-size: 1.6rem;\r\n        &--framed{\r\n            background-color: vars.$lightColor;\r\n            padding: 2rem;\r\n            border-radius: 1.5rem;\r\n            border: 1px solid #C5D9F5;\r\n            margin: 2rem 0;\r\n        }\r\n    }\r\n\r\n    &__details{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n    }\r\n    &__steps{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        list-style-position: inside;\r\n        & > li{\r\n            font-size: vars.$pSize;\r\n            font-family: vars.$mainFontSemibold;\r\n            background-color: vars.$lightColor;\r\n            color: vars.$primaryColor;\r\n            padding: 0.5rem 1.5rem;\r\n            border-radius: 0.8em;\r\n            margin-right: 1rem;\r\n            margin-top: 1rem;\r\n        }\r\n    }\r\n    &__features{\r\n        position: relative;\r\n        & > li {\r\n            margin: 0.5rem 0 0.5rem 1.3rem;\r\n            font-size: vars.$pSize;\r\n            color: vars.$greyColor;\r\n            font-family: vars.$mainFontMedium;\r\n            &::before{\r\n                transform: translateY(-20%);\r\n                left: 0;\r\n                position: absolute;\r\n                color: vars.$primaryColor;\r\n                font-size: 2.8rem;\r\n                content: \"•\";\r\n            }\r\n        }\r\n    }\r\n    &__benefits{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        & > li {\r\n            position: relative;\r\n            margin: 0.5rem 3rem;\r\n            font-size: vars.$pSize;\r\n            font-style: vars.$mainFontMedium;\r\n            &::before{\r\n                left: 0;\r\n                translate: -2.5rem -2px;\r\n                position: absolute;\r\n                content: url(/src/graphics/svg/benefit-icon.svg);\r\n                width: 18px;\r\n            }\r\n        }\r\n        &--residence{\r\n            // max-width: 40%;\r\n            flex-direction: column;\r\n            margin-right: 6rem;\r\n            padding-block: 2rem;\r\n            & > li {\r\n                text-align: end;\r\n                &::before{\r\n                    content: '  ';\r\n                }\r\n                &::after{\r\n                    position: absolute;\r\n                    translate: 1rem -2px;\r\n                    content: url(/src/graphics/png/benefit-icon.png);\r\n                }\r\n            }\r\n        }\r\n        &--vertical{\r\n            flex-direction: column;\r\n        }\r\n    }\r\n\r\n    &__divider{\r\n        height: 1px;\r\n        background-color: vars.$borderColor;\r\n        margin: 2rem 0;\r\n    }\r\n    &__cta {\r\n        margin-top: auto;\r\n    }\r\n    &__price-tag, &__timeline-tag{\r\n        font-size: vars.$pSize;\r\n        position: absolute;\r\n        right: 0;\r\n        text-shadow: 0 2px 40px vars.$lightColor;\r\n    }\r\n    &__price-tag {\r\n        font-family: vars.$mainFontBold;\r\n        color:vars.$primaryColor\r\n    }\r\n    &__timeline-tag{\r\n        translate: 0 100%;\r\n        font-family: vars.$mainFontRegular;\r\n        color:vars.$lightGreyColor\r\n    }\r\n    &__extras{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-between;\r\n        & > li {\r\n            padding: 1rem 0;\r\n            display: flex;\r\n            align-items: center;\r\n            width: 50%;\r\n            & > img {\r\n                border-radius: 1rem;\r\n                padding: 0.7rem;\r\n                background-color: vars.$lightColor;\r\n                width: 6rem;\r\n                height: 6rem;\r\n            }\r\n            & > p { \r\n                margin-left: 0.5rem;\r\n                font-size: 1.4rem;\r\n                font-family: vars.$mainFontSemibold\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\n        &__header{\n            &--mini{\n                grid-template-columns: 64px minmax(0, 1fr);\n                column-gap: 1rem;\n                row-gap: 0.4rem;\n\n                & > .service-card__price-tag,\n                & > .service-card__timeline-tag{\n                    font-size: 1.4rem;\n                }\n\n                & > .service-card__icon{\n                    width: 64px;\n                    padding: 1.4rem;\n                    border-radius: 1.2rem;\n                }\n\n                & > .service-card__title{\n                    line-height: 1.1;\n                }\n            }\n        }\n\n        &--glow{\n            gap: 1rem;\n            & > h4{\n                font-size: vars.$pSize;\n            }\n        }\r\n        &__details{\r\n            gap: 1rem;\r\n        }\r\n        &__steps, &__benefits{\r\n            & > li{\r\n                // margin: 0;\r\n                margin-top: 0.5rem;\r\n                font-size: vars.$pSize * 0.9;\r\n            }\r\n        }\r\n        &__description{\r\n            text-align: justify;\r\n        }\r\n        &__timeline-tag{\r\n            color:vars.$darkColor;\r\n            font-family: vars.$mainFontMedium;\r\n        }\r\n        &__extras{\r\n            & > li{\r\n            justify-content: space-around;\r\n            }\r\n        }\r\n        &__features{\r\n            & > li{\r\n                font-size: 1.4rem;\r\n                font-family: vars.$mainFontRegular\r\n            }\r\n        }\r\n    }\r\n}\n","@use \"./vars\";\r\n\r\n\r\n.scheme{\r\n    position: relative;\r\n    counter-reset: item 0;\r\n\r\n    &-container{\r\n        max-width: 45%;\r\n        &--horizontal {\r\n            width: 100%;\r\n            & > .scheme-container__title{\r\n                margin: 4rem 0 8rem;\r\n            }\r\n        }\r\n        &__title{\r\n            text-align: center;\r\n            font-family: vars.$mainFontSemibold;\r\n            margin-bottom: 5rem;\r\n        }\r\n        &__text{\r\n            margin: 3.4rem 0;\r\n        }\r\n    }\r\n    &__item{\r\n        counter-increment: item;\r\n\r\n        position: relative;\r\n        margin-left: 9rem;\r\n        \r\n        border: 1px solid vars.$borderColor;\r\n        border-radius: 1.5em;\r\n        padding: 2rem;\r\n        margin-bottom: 2.5rem;\r\n        &-title{\r\n\r\n            font-family: vars.$mainFontSemibold;\r\n            &::before{\r\n                position: absolute;\r\n                content: url(/src/graphics/svg/scheme-point.svg);\r\n                width: 50px;\r\n                left: 0;\r\n                translate:-84% 0;\r\n            }\r\n        }\r\n        &-text{\r\n            font-family: vars.$mainFontMedium;\r\n            margin-top: 1.5rem;\r\n        }\r\n\r\n        &::before{\r\n            background-color: vars.$primaryColor;\r\n            font-size: vars.$h4Size;\r\n            font-family: vars.$mainFontSemibold;\r\n            content: counter(item);\r\n            translate: -170% -30%;\r\n            color: #fff;\r\n            padding: 1.5rem 2.1rem;\r\n            border-radius: 100%;\r\n            position: absolute;\r\n            left: 0;\r\n        }\r\n\r\n        &--special{\r\n            background-color: vars.$darkColor;\r\n            color: #fff;\r\n            & > h4{\r\n                color: #fff;\r\n            }\r\n        }\r\n    }\r\n    &__line{\r\n        position: absolute;\r\n        width: 3px;\r\n        height: 95%;\r\n        background-color: vars.$primaryColor;\r\n        left: 24px;\r\n        translate: 0 10px;\r\n    }\r\n\r\n    &--horizontal{\r\n        display: flex;\r\n        justify-content: space-between;\r\n        & > li{\r\n            position: relative;\r\n            background-color: vars.$lightColor;\r\n            margin: 1rem;\r\n            padding: 1rem;\r\n            // max-width: 40%;\r\n            &::before {\r\n                z-index: 2;\r\n                position: absolute;\r\n                left: 50%;\r\n                translate: -50% -80px;\r\n            }\r\n            & > p{\r\n                // font-size: 14px;\r\n                vertical-align: middle;\r\n                text-align: center;\r\n                &::before{\r\n                    position: absolute;\r\n                    top: 0;\r\n                    left: 50%;\r\n                    rotate: 90deg;\r\n                    translate: -50% -25px;\r\n                }\r\n            }\r\n        }\r\n        & > .scheme__line{\r\n            height: 3px;\r\n            width: 70%;\r\n            translate: 0 0;\r\n            &--position1{\r\n                translate: 11% -30px;\r\n            }\r\n            &--position2{\r\n                translate: 12% -30px;\r\n                width: 75%;\r\n            }\r\n            &--position3{\r\n                translate: 22% -30px;\r\n                width: 65%;\r\n            }\r\n            &--position4{\r\n                translate: 16% -30px;\r\n                width: 70%;\r\n            }\r\n        }\r\n    }\r\n    &--bank{\r\n        // outline: 1px dashed salmon;\r\n        & > .scheme__line{\r\n            height: 90%;\r\n        }\r\n        & > .scheme__item{\r\n            & > .scheme__item-title{\r\n                font-size: 2rem;\r\n            }\r\n            & > .scheme__item-text{\r\n                font-family: vars.$mainFontRegular;\r\n                color: vars.$greyColor\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n@media (max-width: vars.$mobile) {\r\n    .scheme-container {\r\n        max-width: 100%;\r\n    }\r\n\r\n    .scheme-container--horizontal {\r\n        width: 100%;\r\n        max-width: 100%;\r\n        overflow-x: hidden;\r\n\r\n        & > .scheme-container__title {\r\n            margin: 3rem 0 3.6rem;\r\n        }\r\n    }\r\n\r\n    .scheme--horizontal {\r\n        display: block;\r\n        width: 100%;\r\n        max-width: 100%;\r\n        padding: 0;\r\n\r\n        & > .scheme__item {\r\n            margin: 0 0 1rem 8rem;\r\n            padding: 2rem;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 1.5em;\r\n            background-color: vars.$white;\r\n            min-width: 0;\r\n\r\n            &::before {\r\n                top: 50%;\r\n                left: 0;\r\n                translate: -135% -50%;\r\n                // padding: 1.5rem 1.6rem;\r\n                font-size: vars.$h5Size;\r\n            }\r\n\r\n            & > p {\r\n                font-family: vars.$mainFontMedium;\r\n                overflow-wrap: anywhere;\r\n\r\n                &::before {\r\n                    top: 50%;\r\n                    left: 0;\r\n                    rotate: 0deg;\r\n                    translate: -84% -50%;\r\n                }\r\n            }\r\n        }\r\n\r\n        & > .scheme__line {\r\n            width: 3px;\r\n            height: auto;\r\n            left: 34px;\r\n            top: 6rem;\r\n            bottom: 5.8rem;\r\n            translate: 0 0;\r\n\r\n            &--position1,\r\n            &--position2,\r\n            &--position3,\r\n            &--position4 {\r\n                width: 3px;\r\n                translate: 0 0;\r\n            }\r\n        }\r\n    }\r\n}\r\n"]}